import React, { useState } from "react";
import "../styles/dashboard.css";

const CustomerDashboard = () => {
  const [search, setSearch] = useState("");

  const workers = [
    { id: 1, name: "Ravi", skill: "Plumber", location: "Mysore" },
    { id: 2, name: "Arjun", skill: "Electrician", location: "Nearby" }
  ];

  return (
    <div className="dashboard-container">

      {/* TOPBAR */}
      <div className="topbar">
        <h3>Customer Dashboard</h3>
        <button className="btn-outline">Logout</button>
      </div>

      <div className="grid grid-2">

        {/* SEARCH */}
        <div className="card full">
          <input
            placeholder="Search workers..."
            value={search}
            onChange={(e) => setSearch(e.target.value)}
            style={{
              width: "100%",
              padding: "10px",
              borderRadius: "8px",
              border: "1px solid #e5e7eb"
            }}
          />
        </div>

        {/* WORKERS */}
        {workers
          .filter(w =>
            w.skill.toLowerCase().includes(search.toLowerCase())
          )
          .map((w) => (
            <div key={w.id} className="card">
              <h4>{w.name}</h4>
              <p>{w.skill}</p>
              <p>{w.location}</p>

              <button className="btn-green">Hire</button>
            </div>
          ))}

      </div>

    </div>
  );
};

export default CustomerDashboard;
